script:
function __excelCtx(ctx){
  function doc(){ return ctx && ctx.$el ? ctx.$el.ownerDocument : document; }
  function report(){ var d=doc(); return d.querySelector('.page_report_view_container') && d.querySelector('.page_report_view_container').__vue__; }
  function sheetView(){ var d=doc(); return d.querySelector('.report-view-main') && d.querySelector('.report-view-main').__vue__; }
  function sheet(){ var vm=sheetView(); if(!vm || !vm.univerAPI) throw new Error('univerAPI not found'); return vm.univerAPI.getActiveWorkbook().getActiveSheet(); }
  function note(msg, detail){
    window.__wos4ExcelLastAction={message:msg, detail:detail, at:new Date().toISOString()};
  }
  function colName(index){ var s=''; index++; while(index>0){ var m=(index-1)%26; s=String.fromCharCode(65+m)+s; index=Math.floor((index-1)/26); } return s; }
  function esc(v){ return String(v==null?'':v).replace(/[&<>\"]/g,function(ch){ return {'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;'}[ch]; }); }
  function currentRows(sh, rowCount, colCount){
    var rows=[];
    try {
      var block = sh.getRange('A1:'+colName(colCount-1)+rowCount);
      if(block && block.getValues){ rows = block.getValues() || []; }
    } catch(e) { rows=[]; }
    for(var r=0;r<rowCount;r++){
      rows[r]=rows[r] || [];
      for(var c=0;c<colCount;c++){
        if(rows[r][c]===undefined){
          try {
            var cell=sh.getRange(colName(c)+(r+1));
            rows[r][c]=cell.getDisplayValue ? cell.getDisplayValue() : cell.getValue();
          } catch(e2) { rows[r][c]=''; }
        }
      }
    }
    return rows;
  }
  return {doc:doc, report:report, sheetView:sheetView, sheet:sheet, note:note, colName:colName, esc:esc, currentRows:currentRows};
}

try {
  var x=__excelCtx(this), rv=x.report(), sh=x.sheet();
  if(!rv || !rv.Print) throw new Error('Report Print not found');
  var rowCount=163, colCount=8;
  var options={
    type:0,
    size:{type:3,width:1100,height:820},
    align:'center',
    repeatHeader:true,
    title:{startRow:0,endRow:0},
    header:{startRow:1,endRow:1},
    tail:{startRow:162,endRow:162},
    pageBreak:{h:[44,89,134],v:[]}
  };
  window.__wos4ExcelLastPrintOptions=options;
  window.__wos4ExcelFallbackUsedCurrentSheet=false;
  window.__wos4ExcelFallbackMutatedSheet=false;
  window.__wos4ExcelPrintImageIncluded=false;

  function valuesSample(rows){
    return {A1:rows[0]&&rows[0][0], B1:rows[0]&&rows[0][1], A2:rows[1]&&rows[1][0], H2:rows[1]&&rows[1][7], A163:rows[162]&&rows[162][0]};
  }

  function fallbackPrint(rows){
    var imgUrl = window.__wos4ExcelPrintImageUrl || window.__wos4ExcelImageUrl || '';
    var titleText = rows[0].filter(function(v){ return String(v||'').trim(); }).join('  ');
    if(!titleText) titleText='WOS4 Excel Current Sheet Print';
    var header = rows[1].map(function(v,i){ return String(v||'').trim() || x.colName(i); });
    var footerText = rows[162].filter(function(v){ return String(v||'').trim(); }).join('  ');
    if(!footerText) footerText='Printed from current sheet';
    function img(cls){ return imgUrl ? '<img class="'+cls+'" src="'+imgUrl+'" />' : ''; }
    function td(v, cls, extra){ return '<td class="'+(cls||'')+'">'+x.esc(v)+(extra||'')+'</td>'; }
    var html='<!doctype html><html><head><meta charset="utf-8"><title>'+x.esc(titleText)+'</title><style>'+
      '@page{size:A4 landscape;margin:12mm 10mm;}*{box-sizing:border-box;}body{margin:0;font-family:Arial,"Microsoft YaHei",sans-serif;color:#111827;background:#fff;}table{border-collapse:collapse;width:100%;table-layout:fixed;font-size:10px;}thead{display:table-header-group;}tfoot{display:table-footer-group;}th,td{border:1px solid #cbd5e1;padding:4px 5px;min-height:22px;vertical-align:middle;word-break:break-word;}thead .title th{background:#1d4ed8;color:#fff;font-size:16px;line-height:28px;text-align:center;}thead .header th{background:#0f172a;color:#fff;font-weight:700;}tfoot td{background:#dbeafe;color:#1e3a8a;font-weight:700;text-align:center;font-size:11px;}tbody tr:nth-child(even) td{background:#f8fafc;}.status{font-weight:700;color:#15803d;}.amount{text-align:right;}.cell-img{max-width:52px;max-height:30px;display:inline-block;margin-left:4px;vertical-align:middle;}.body-img{max-width:80px;max-height:46px;display:block;margin:2px auto;}.print-meta{position:fixed;right:10mm;bottom:5mm;font-size:9px;color:#64748b;}</style></head><body><table><thead><tr class="title"><th colspan="'+colCount+'">'+x.esc(titleText)+'</th></tr><tr class="header">';
    for(var h=0;h<colCount;h++) html+='<th>'+x.esc(header[h])+(h===7?img('cell-img'):'')+'</th>';
    html+='</tr></thead><tfoot><tr><td colspan="'+colCount+'">'+x.esc(footerText)+'</td></tr></tfoot><tbody>';
    for(var r=2;r<162;r++){
      html+='<tr>';
      for(var c=0;c<colCount;c++){
        var cls = c===4 ? 'amount' : (c===5 ? 'status' : '');
        var extra = (imgUrl && r===4 && c===6) ? img('body-img') : '';
        html+=td(rows[r][c], cls, extra);
      }
      html+='</tr>';
    }
    html+='</tbody></table><div class="print-meta">Current sheet fallback print</div></body></html>';
    window.__wos4ExcelLastPrintHtml=html;
    window.__wos4ExcelFallbackUsedCurrentSheet=true;
    window.__wos4ExcelFallbackMutatedSheet=false;
    window.__wos4ExcelPrintImageIncluded=html.indexOf('<img')>=0;
    if(window.__wos4ExcelDryRunPrint===true){ x.note('PRINT DRY RUN CURRENT SHEET', valuesSample(rows)); return; }
    var iframe=x.doc().createElement('iframe');
    iframe.style.position='fixed'; iframe.style.right='0'; iframe.style.bottom='0'; iframe.style.width='0'; iframe.style.height='0'; iframe.style.border='0';
    x.doc().body.appendChild(iframe);
    iframe.onload=function(){
      setTimeout(function(){
        try { iframe.contentWindow.focus(); iframe.contentWindow.print(); x.note('PRINT FALLBACK CURRENT SHEET', valuesSample(rows)); }
        finally { setTimeout(function(){ try{ iframe.remove(); }catch(_e){} }, 1500); }
      }, 120);
    };
    iframe.srcdoc=html;
  }

  var rows=x.currentRows(sh,rowCount,colCount);
  window.__wos4ExcelBeforePrintDataSample=valuesSample(rows);
  var beforePrintFired=false;
  var onBefore=function(){ beforePrintFired=true; window.__wos4ExcelNativePrintStarted=true; };
  window.addEventListener('beforeprint', onBefore, {once:true});
  var nativeResult=null;
  try { nativeResult=rv.Print(0, {}, options); } catch(nativeError) { window.__wos4ExcelNativePrintError=String(nativeError && nativeError.message || nativeError); }
  window.__wos4ExcelNativePrintResult=nativeResult || null;
  setTimeout(function(){
    try { window.removeEventListener('beforeprint', onBefore); } catch(_e) {}
    if(!beforePrintFired) fallbackPrint(rows);
  }, window.__wos4ExcelPrintFallbackDelay || 1800);
  x.note('PRINT REQUESTED CURRENT SHEET', valuesSample(rows));
} catch(e) {
  try { window.__wos4ExcelLastAction={message:'PRINT ERROR '+e.message, at:new Date().toISOString()}; } catch(_) {}
}
